<blockquote class="blockquote-center">阿拉伯浮点数字转换成中文数字</blockquote>
<!-- more -->

```javascript
var nNum = 5566555234.123,
    sNum = nNum.toString(),
    aNum = sNum.split('.'),
    sNum = {
        '0': '零',
        '1': '一',
        '2': '二',
        '3': '三',
        '4': '四',
        '5': '五',
        '6': '六',
        '7': '七',
        '8': '八',
        '9': '九',
        '10': '十'
    },
    aInterger = ["元", "十", "百", "千", "万", "十", "百", "千", "亿", "十"],
    aPoint = ['毛', '分', '里'],
    sTmp = '';


for (var i = 0; i < aNum.length; i++) {
    var nSize = aNum[i].length;

    if (!i) {
        aInterger.length = nSize;
        aInterger.reverse()
    }

    for (var n = 0; n < nSize; n++) {
        sTmp += sNum[aNum[i][n]];

        if (i) {
            sTmp += aPoint[n];
        } else {
            sTmp += aInterger[n];
        }
    }
}

console.log(sTmp);
```
